"use client";

import * as React from "react";
import {
  motion,
  useMotionTemplate,
  useMotionValue,
  useSpring,
  useTransform,
} from "motion/react";

import { cn } from "@/lib/utils";
import {
  useExperienceViewport,
  useFinePointer,
  usePrefersReducedMotion,
} from "@/components/experience/experience-runtime";

type CursorAmbientProps = Omit<React.ComponentProps<"div">, "children"> & {
  base: React.ReactNode;
  reveal: React.ReactNode;
  children?: React.ReactNode;
  cursorLabel?: string;
  label: string;
  lensClassName?: string;
  lensSize?: number;
  tabletLensSize?: number;
};

/**
 * A kinetic cursor lens that reveals a second visual state. It is intentionally
 * scoped to its canvas and becomes a static base visual on touch/reduced motion.
 */
export function CursorAmbient({
  base,
  children,
  className,
  cursorLabel = "EXPLORE",
  label,
  lensClassName,
  lensSize = 220,
  onPointerEnter,
  onPointerLeave,
  onPointerMove,
  reveal,
  style,
  tabletLensSize,
  ...props
}: CursorAmbientProps) {
  const x = useMotionValue(0);
  const y = useMotionValue(0);
  const radius = useMotionValue(0);
  const opacity = useMotionValue(0);
  const smoothX = useSpring(x, { stiffness: 420, damping: 38, mass: 0.35 });
  const smoothY = useSpring(y, { stiffness: 420, damping: 38, mass: 0.35 });
  const smoothRadius = useSpring(radius, { stiffness: 240, damping: 25, mass: 0.3 });
  const smoothOpacity = useSpring(opacity, { stiffness: 260, damping: 28 });
  const prefersReducedMotion = usePrefersReducedMotion();
  const finePointer = useFinePointer();
  const viewport = useExperienceViewport();
  const activeLensSize = viewport === "tablet" ? tabletLensSize ?? Math.min(lensSize, 190) : lensSize;
  const ringX = useTransform(smoothX, (value) => value - activeLensSize / 2);
  const ringY = useTransform(smoothY, (value) => value - activeLensSize / 2);
  const clipPath = useMotionTemplate`circle(${smoothRadius}px at ${smoothX}px ${smoothY}px)`;
  const [activeLabel, setActiveLabel] = React.useState(cursorLabel);
  // rAF-coalesced label lookup: the `.closest` walk runs at most once per frame.
  const labelLookupRef = React.useRef({ frame: 0, target: null as HTMLElement | null });

  React.useEffect(() => {
    const labelLookup = labelLookupRef.current;
    return () => cancelAnimationFrame(labelLookup.frame);
  }, []);

  const scheduleLabelUpdate = (target: HTMLElement) => {
    const labelLookup = labelLookupRef.current;
    labelLookup.target = target;
    if (labelLookup.frame) return;
    labelLookup.frame = requestAnimationFrame(() => {
      labelLookup.frame = 0;
      const hit = labelLookup.target?.closest<HTMLElement>("[data-cursor-label]");
      const next = hit?.dataset.cursorLabel || cursorLabel;
      setActiveLabel((current) => (current === next ? current : next));
    });
  };

  const canFollow = finePointer && !prefersReducedMotion;
  const handlePointerMove = (event: React.PointerEvent<HTMLDivElement>) => {
    if (canFollow) {
      const rect = event.currentTarget.getBoundingClientRect();
      x.set(event.clientX - rect.left);
      y.set(event.clientY - rect.top);
      radius.set(activeLensSize / 2);
      opacity.set(1);
      scheduleLabelUpdate(event.target as HTMLElement);
    }
    onPointerMove?.(event);
  };
  const handlePointerEnter = (event: React.PointerEvent<HTMLDivElement>) => {
    if (canFollow) {
      const rect = event.currentTarget.getBoundingClientRect();
      x.set(event.clientX - rect.left);
      y.set(event.clientY - rect.top);
      radius.set(activeLensSize / 2);
      opacity.set(1);
    }
    onPointerEnter?.(event);
  };
  const handlePointerLeave = (event: React.PointerEvent<HTMLDivElement>) => {
    const labelLookup = labelLookupRef.current;
    radius.set(0);
    opacity.set(0);
    cancelAnimationFrame(labelLookup.frame);
    labelLookup.frame = 0;
    labelLookup.target = null;
    setActiveLabel(cursorLabel);
    onPointerLeave?.(event);
  };

  return (
    <div
      role="region"
      aria-label={label}
      data-cursor-lens
      data-experience-viewport={viewport}
      className={cn("relative isolate overflow-hidden", className)}
      style={style}
      onPointerEnter={handlePointerEnter}
      onPointerLeave={handlePointerLeave}
      onPointerMove={handlePointerMove}
      {...props}
    >
      <div className="absolute inset-0">{base}</div>
      <motion.div
        aria-hidden
        className="pointer-events-none absolute inset-0 will-change-[clip-path]"
        style={{ clipPath }}
      >
        {reveal}
      </motion.div>
      {children ? <div className="absolute inset-0 z-10">{children}</div> : null}

      {canFollow ? (
        <motion.div
          aria-hidden
          className={cn(
            "pointer-events-none absolute left-0 top-0 z-30 grid rounded-full border border-current text-[0.62rem] font-semibold tracking-[0.18em] will-change-transform",
            lensClassName,
          )}
          style={{
            width: activeLensSize,
            height: activeLensSize,
            x: ringX,
            y: ringY,
            opacity: smoothOpacity,
          }}
        >
          <span className="place-self-center">{activeLabel}</span>
        </motion.div>
      ) : null}
    </div>
  );
}

export const CursorLens = CursorAmbient;

"use client";

import * as React from "react";

export const EXPERIENCE_BREAKPOINTS = {
  tablet: 640,
  desktop: 1025,
} as const;

export type ExperienceViewport = "mobile" | "tablet" | "desktop";

export type ExperienceResponsiveValue<T> = T | {
  /** Mobile-first value, also used during SSR/hydration. */
  mobile: T;
  /** iPad/tablet value. Falls back to `mobile` when omitted. */
  tablet?: T;
  /** Wide-screen value. Falls back to `tablet`, then `mobile`. */
  desktop?: T;
};

const subscribeToHydration = () => () => undefined;

export function useHydrated() {
  return React.useSyncExternalStore(subscribeToHydration, () => true, () => false);
}

export function useMediaQuery(query: string, serverValue = false) {
  const subscribe = React.useCallback(
    (onChange: () => void) => {
      const media = window.matchMedia(query);
      media.addEventListener("change", onChange);
      return () => media.removeEventListener("change", onChange);
    },
    [query],
  );
  const getSnapshot = React.useCallback(() => window.matchMedia(query).matches, [query]);
  return React.useSyncExternalStore(subscribe, getSnapshot, () => serverValue);
}

/**
 * Hydration-safe reduced-motion preference: false on the server and during
 * hydration, then live. Replaces the repeated `mounted && useReducedMotion()`
 * pattern.
 */
export function usePrefersReducedMotion() {
  return useMediaQuery("(prefers-reduced-motion: reduce)");
}

/** True on touch-first devices; use to swap pointer effects for static or rail modes. */
export function useCoarsePointer() {
  return useMediaQuery("(pointer: coarse)");
}

/** True only when a hover-capable precise pointer is present. */
export function useFinePointer() {
  return useMediaQuery("(hover: hover) and (pointer: fine)");
}

/**
 * Shared mobile-first viewport contract for every experience primitive.
 *
 * Mobile: < 640px · tablet/iPad: 640–1024px · desktop: >= 1025px.
 * Pointer capability remains a separate signal because an iPad can gain a
 * trackpad without changing its layout profile.
 */
export function useExperienceViewport(): ExperienceViewport {
  const tablet = useMediaQuery(`(min-width: ${EXPERIENCE_BREAKPOINTS.tablet}px)`);
  const desktop = useMediaQuery(`(min-width: ${EXPERIENCE_BREAKPOINTS.desktop}px)`);
  if (desktop) return "desktop";
  if (tablet) return "tablet";
  return "mobile";
}

export function resolveExperienceValue<T>(
  value: ExperienceResponsiveValue<T>,
  viewport: ExperienceViewport,
): T {
  if (typeof value !== "object" || value === null || !("mobile" in value)) return value;
  if (viewport === "desktop") return value.desktop ?? value.tablet ?? value.mobile;
  if (viewport === "tablet") return value.tablet ?? value.mobile;
  return value.mobile;
}

/** Conservative raster/WebGL supersampling budget for each layout profile. */
export function getExperienceDprCap(width: number) {
  if (width < EXPERIENCE_BREAKPOINTS.tablet) return 1;
  if (width < EXPERIENCE_BREAKPOINTS.desktop) return 1.25;
  return 1.6;
}

export function clamp01(value: number) {
  return Math.min(1, Math.max(0, value));
}

export function mix(from: number, to: number, amount: number) {
  return from + (to - from) * amount;
}

export function damp(current: number, target: number, smoothing: number, deltaSeconds: number) {
  return mix(current, target, 1 - Math.exp(-Math.max(0.01, smoothing) * deltaSeconds));
}

/** Returns the frames sorted by `at`, reusing the input when it is already ordered. */
export function sortKeyframes<T extends { at: number }>(frames: T[]): T[] {
  for (let index = 1; index < frames.length; index += 1) {
    if (frames[index - 1]!.at > frames[index]!.at) {
      return [...frames].sort((left, right) => left.at - right.at);
    }
  }
  return frames;
}

export function resolveKeyframes<T extends { at: number }>(
  frames: T[],
  progress: number,
): { from: T; to: T; mix: number } {
  if (frames.length === 0) throw new Error("Experience keyframes cannot be empty.");
  const sorted = sortKeyframes(frames);
  if (progress <= sorted[0]!.at) return { from: sorted[0]!, to: sorted[0]!, mix: 0 };
  for (let index = 0; index < sorted.length - 1; index += 1) {
    const from = sorted[index]!;
    const to = sorted[index + 1]!;
    if (progress <= to.at) {
      const span = Math.max(0.0001, to.at - from.at);
      return { from, to, mix: clamp01((progress - from.at) / span) };
    }
  }
  const final = sorted.at(-1)!;
  return { from: final, to: final, mix: 0 };
}

export function supportsWebGL() {
  try {
    const canvas = document.createElement("canvas");
    return Boolean(
      canvas.getContext("webgl2", { failIfMajorPerformanceCaveat: true })
      || canvas.getContext("webgl", { failIfMajorPerformanceCaveat: true }),
    );
  } catch {
    return false;
  }
}
